(() => {
'use strict';
const BOOKING_URL = '';
if (BOOKING_URL) {
document.querySelectorAll('[data-book-link]').forEach(a => {
a.href = BOOKING_URL;
a.target = '_blank';
a.rel = 'noopener';
});
}
document.documentElement.classList.add('js-ready');
const reduceMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
const nav = document.querySelector('.nav');
if (nav) {
const update = () => {
nav.classList.toggle('is-scrolled', window.scrollY > 24);
};
update();
window.addEventListener('scroll', update, { passive: true });
}
(function navConverge() {
const brand = document.querySelector('.nav__brand');
const ctaShift = document.querySelector('.nav__cta-shift');
const links = document.querySelector('.nav__links');
const hero = document.querySelector('.hero');
const setFinal = () => {
[brand, ctaShift].forEach(el => {
if (el) { el.style.transform = 'translateX(0)'; el.style.opacity = '1'; }
});
if (links) links.style.opacity = '1';
};
if (reduceMotion) return;
if (!hero || !brand) { setFinal(); return; }
const COMPLETE_AT = 0.6;
const easeOut = t => t * (2 - t);
const offsetFor = () => (window.innerWidth < 600 ? 22 : 40);
let ticking = false;
let locked = false;
const apply = () => {
ticking = false;
const heroHeight = hero.offsetHeight || 1;
const raw = Math.min(Math.max(window.scrollY / (heroHeight * COMPLETE_AT), 0), 1);
const p = easeOut(raw);
if (p >= 1) {
if (locked) return;
setFinal();
locked = true;
return;
}
locked = false;
const out = (offsetFor() * (1 - p)).toFixed(2);
const fade = (0.7 + 0.3 * p).toFixed(3);
brand.style.transform = `translateX(-${out}px)`;
brand.style.opacity = fade;
if (ctaShift) {
ctaShift.style.transform = `translateX(${out}px)`;
ctaShift.style.opacity = fade;
}
if (links) links.style.opacity = p.toFixed(3);
};
const onScroll = () => {
if (!ticking) { ticking = true; requestAnimationFrame(apply); }
};
apply();
window.addEventListener('scroll', onScroll, { passive: true });
window.addEventListener('resize', onScroll, { passive: true });
})();
const toggle = document.querySelector('.nav__toggle');
const drawer = document.querySelector('.nav__drawer');
if (toggle && drawer) {
const close = () => {
toggle.setAttribute('aria-expanded', 'false');
drawer.setAttribute('aria-hidden', 'true');
document.body.classList.remove('nav-open');
};
const open = () => {
toggle.setAttribute('aria-expanded', 'true');
drawer.setAttribute('aria-hidden', 'false');
document.body.classList.add('nav-open');
};
toggle.addEventListener('click', () => {
const isOpen = toggle.getAttribute('aria-expanded') === 'true';
isOpen ? close() : open();
});
drawer.addEventListener('click', e => {
if (e.target.matches('a')) close();
});
document.addEventListener('keydown', e => {
if (e.key === 'Escape' && toggle.getAttribute('aria-expanded') === 'true') close();
});
window.matchMedia('(min-width: 960px)').addEventListener('change', e => {
if (e.matches) close();
});
}
const reveals = document.querySelectorAll('.reveal, .reveal--stagger');
if (reveals.length && !reduceMotion && 'IntersectionObserver' in window) {
const io = new IntersectionObserver(entries => {
entries.forEach(entry => {
if (entry.isIntersecting) {
entry.target.classList.add('is-visible');
io.unobserve(entry.target);
}
});
}, { rootMargin: '0px 0px 25% 0px', threshold: 0 });
reveals.forEach(el => io.observe(el));
setTimeout(() => reveals.forEach(el => el.classList.add('is-visible')), 1200);
} else {
reveals.forEach(el => el.classList.add('is-visible'));
}
const counters = document.querySelectorAll('[data-counter]');
if (counters.length && 'IntersectionObserver' in window) {
const easeOutCubic = t => 1 - Math.pow(1 - t, 3);
const animate = el => {
const target = parseFloat(el.dataset.counter);
const suffix = el.dataset.suffix || '';
const prefix = el.dataset.prefix || '';
const duration = reduceMotion ? 0 : 1600;
const start = performance.now();
const tick = now => {
const t = Math.min((now - start) / duration, 1);
const value = target * easeOutCubic(t);
const display = Number.isInteger(target)
? Math.round(value).toLocaleString('en-GB')
: value.toFixed(1);
el.textContent = `${prefix}${display}${suffix}`;
if (t < 1) requestAnimationFrame(tick);
};
requestAnimationFrame(tick);
};
const io = new IntersectionObserver(entries => {
entries.forEach(entry => {
if (entry.isIntersecting) {
animate(entry.target);
io.unobserve(entry.target);
}
});
}, { threshold: 0.5 });
counters.forEach(el => io.observe(el));
}
const heroBg = document.querySelector('[data-parallax]');
if (heroBg && !reduceMotion) {
let ticking = false;
const onScroll = () => {
if (ticking) return;
ticking = true;
requestAnimationFrame(() => {
const y = window.scrollY;
if (y < window.innerHeight * 1.3) {
heroBg.style.transform = `translate3d(0, ${y * 0.12}px, 0) scale(1.03)`;
}
ticking = false;
});
};
window.addEventListener('scroll', onScroll, { passive: true });
}
if (location.hash) {
setTimeout(() => {
const el = document.querySelector(CSS.escape(location.hash));
if (el) el.scrollIntoView({ behavior: 'smooth', block: 'start' });
}, 80);
}
const path = location.pathname.replace(/\/$/, '') || '/index.html';
document.querySelectorAll('.nav__link').forEach(link => {
const href = link.getAttribute('href') || '';
const normalised = href.replace(/\/$/, '');
if (normalised && (normalised === path || (normalised !== '/' && path.endsWith(normalised)))) {
link.setAttribute('aria-current', 'page');
}
});
const yr = document.querySelector('[data-current-year]');
if (yr) yr.textContent = new Date().getFullYear();
})();